   239	    pub fn organized_lints(&mut self, document: &Document) -> BTreeMap<String, Vec<Lint>> {
   240	        let mut results = BTreeMap::new();
   241	
   242	        // Normal linters
   243	        for (key, linter) in &mut self.linters {
   244	            if self.config.is_rule_enabled(key) {
   245	                results.insert(key.to_owned(), linter.lint(document));
   246	            }
   247	        }
   248	
   249	        // Expr linters
   250	        for chunk in document.iter_chunks() {
   251	            let Some(chunk_span) = chunk.span() else {
   252	                continue;
   253	            };
   254	
   255	            let chunk_chars = document.get_span_content(&chunk_span);
   256	            let config_hash = self.hasher_builder.hash_one(&self.config);
   257	            let char_hash = self.hasher_builder.hash_one(chunk_chars);
   258	            let cache_key = (char_hash, config_hash);
   259	
   260	            let chunk_results = if let Some(hit) = self.chunk_expr_cache.get(&cache_key) {
   261	                hit.clone()
   262	            } else {
   263	                let mut pattern_lints = BTreeMap::new();
   264	
   265	                for (key, linter) in &mut self.chunk_expr_linters {
   266	                    if self.config.is_rule_enabled(key) {
   267	                        let lints =
   268	                            run_on_chunk(linter, chunk, document.get_source()).map(|mut l| {
   269	                                l.span.pull_by(chunk_span.start);
   270	                                l
   271	                            });
   272	
   273	                        pattern_lints.insert(key.clone(), lints.collect());
   274	                    }
   275	                }
   276	
   277	                let pattern_lints = Lrc::new(pattern_lints);
   278	
   279	                self.chunk_expr_cache.put(cache_key, pattern_lints.clone());
   280	                pattern_lints
   281	            };
   282	
   283	            for (key, vec) in chunk_results.iter() {
   284	                results
   285	                    .entry(key.to_owned())
   286	                    .or_default()
   287	                    .extend(vec.iter().cloned().map(|mut lint| {
   288	                        // Bring the spans back into document-space
   289	                        lint.span.push_by(chunk_span.start);
   290	                        lint
   291	                    }));
   292	            }
   293	        }
   294	
   295	        results
   296	    }
