    69	impl<T: Dictionary> Linter for SpellCheck<T> {
    70	    fn lint(&mut self, document: &Document) -> Vec<Lint> {
    71	        let mut lints = Vec::new();
    72	
    73	        for word in document.iter_words() {
    74	            let word_chars = document.get_span_content(&word.span);
    75	
    76	            if let Some(metadata) = word.kind.as_word().unwrap()
    77	                && metadata.dialects.is_dialect_enabled(self.dialect)
    78	                && (self.dictionary.contains_exact_word(word_chars)
    79	                    || self.dictionary.contains_exact_word(&word_chars.to_lower()))
    80	            {
    81	                continue;
    82	            };
    83	
    84	            let mut possibilities = self.suggest_correct_spelling(word_chars);
    85	
    86	            // If the misspelled word is capitalized, capitalize the results too.
    87	            if let Some(mis_f) = word_chars.first()
    88	                && mis_f.is_uppercase()
    89	            {
    90	                for sug_f in possibilities.iter_mut().filter_map(|w| {
    91	                    // Skip words that have uppercase chars in any position except the first.
    92	                    // (For words with specific capitalization, like 'macOS')
    93	                    w.iter()
    94	                        .skip(1)
    95	                        .all(|c| !c.is_uppercase())
    96	                        .then_some(w.first_mut())
    97	                        .flatten()
    98	                }) {
    99	                    *sug_f = sug_f.to_uppercase().next().unwrap();
   100	                }
   101	            }
   102	
   103	            let suggestions: Vec<_> = possibilities
   104	                .iter()
   105	                .map(|sug| Suggestion::ReplaceWith(sug.to_vec()))
   106	                .collect();
   107	
   108	            // If there's only one suggestion, save the user a step in the GUI
   109	            let message = if suggestions.len() == 1 {
   110	                format!(
   111	                    "Did you mean `{}`?",
   112	                    possibilities.first().unwrap().iter().collect::<String>()
   113	                )
   114	            } else {
   115	                format!(
   116	                    "Did you mean to spell `{}` this way?",
   117	                    document.get_span_content_str(&word.span)
   118	                )
   119	            };
   120	
   121	            lints.push(Lint {
   122	                span: word.span,
   123	                lint_kind: LintKind::Spelling,
   124	                suggestions,
   125	                message,
   126	                priority: 63,
   127	            })
   128	        }
   129	
   130	        lints
   131	    }
   132	
   133	    fn description(&self) -> &'static str {
   134	        "Looks and provides corrections for misspelled words."
   135	    }
   136	}
