// Quick repro: Run the LintGroup on "kindof" and check which lints trigger
use std::sync::Arc;
use harper_core::spell::FstDictionary;
use harper_core::{Dialect, Document, linting::{LintGroup, Linter}, remove_overlaps};

fn main() {
    let dict = Arc::new(FstDictionary::curated());
    let mut group = LintGroup::new_curated(dict, Dialect::American);

    let doc = Document::new_plain_english_curated("I want to try this insteadof that.");

    let lints = group.lint(&doc);

    println!("=== Before remove_overlaps ===");
    for lint in &lints {
        println!("  span: {:?}, priority: {}, message: {}", lint.span, lint.priority, lint.message);
    }

    let mut lints_dedup = lints.clone();
    remove_overlaps(&mut lints_dedup);

    println!("\n=== After remove_overlaps ===");
    for lint in &lints_dedup {
        println!("  span: {:?}, priority: {}, message: {}", lint.span, lint.priority, lint.message);
    }

    // Check which linter names are present
    let named = group.organized_lints(&doc);
    println!("\n=== By rule name ===");
    for (name, lints) in &named {
        println!("  {}: {} lints", name, lints.len());
        for lint in lints {
            println!("    span: {:?}, priority: {}, message: {}", lint.span, lint.priority, lint.message);
        }
    }
}
