/// Reproduction test for issue where SplitWords doesn't engage when SpellCheck is also active.
    #[test]
    fn split_words_engages_with_spellcheck() {
        use crate::remove_overlaps_map;

        let dict = Arc::new(FstDictionary::curated());
        let mut group = LintGroup::new_curated(dict, Dialect::American);

        let doc = Document::new_plain_english_curated("I want to try this insteadof that.");

        let mut named = group.organized_lints(&doc);

        // Before overlap removal, both SplitWords and SpellCheck should have lints
        let split_before = named.get("SplitWords").map(|v| v.len()).unwrap_or(0);
        let spell_before = named.get("SpellCheck").map(|v| v.len()).unwrap_or(0);
        dbg!(split_before, spell_before);
        assert!(split_before > 0, "SplitWords should produce a lint for 'insteadof'");
        assert!(spell_before > 0, "SpellCheck should produce a lint for 'insteadof'");

        remove_overlaps_map(&mut named);

        let split_after = named.get("SplitWords").map(|v| v.len()).unwrap_or(0);
        let spell_after = named.get("SpellCheck").map(|v| v.len()).unwrap_or(0);
        dbg!(split_after, spell_after);

        // SplitWords should survive overlap removal because it has a lower priority (more specific)
        assert!(split_after > 0, "SplitWords lint should survive overlap removal");
    }
}

